const LINM_SHELL_PREFIX = '/kpi';

/** Browser URL path used as MemoryRouter location (single-spa / standalone).
 *  Strips shell mount prefix so MFE routes remain clean (tc/kh/*, tc/bc/*, tc/fpc/*). */
export function getBrowserRouterPath(): string {
  if (typeof window === 'undefined') return '/';
  let path = `${window.location.pathname}${window.location.search}${window.location.hash}`;
  if (path.startsWith(LINM_SHELL_PREFIX)) {
    path = path.slice(LINM_SHELL_PREFIX.length) || '/';
  }
  return path;
}
