import React from 'react';
import { MemoryRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import './styles/reportPrint.css';
import { AppLayout } from './components/layout/AppLayout';
import { SimpleNotFoundPage } from '@linm-soft-org/linm-web-common-components';
import { isStandalone, showDevNav } from './dev/isStandalone';
import { StandaloneMockNav } from './standalone/StandaloneMockNav';
import { StandaloneMockTopbar } from './standalone/StandaloneMockTopbar';
import { StandaloneShell } from './standalone/StandaloneShell';
import { MemoryRouterSync } from './router/MemoryRouterSync';
import { getBrowserRouterPath } from './routing/routerPaths';
import type { IRootProps } from './types/IRootProps';

const pageSuspenseStyles = { fallback: 'page-suspense-fallback' };

const DevPage = React.lazy(() => import('./dev/DevPage'));
const DevFpcSampleDataPage = React.lazy(() => import('./dev/DevFpcSampleDataPage'));

// ── FPC / KPI Pages ────────────────────────────────────────────────────────
const DailyCashForecastPage = React.lazy(() => import('./pages/Fpc/DailyCashForecastPage/DailyCashForecastPage'));
const CeoCashTodayPage     = React.lazy(() => import('./pages/Fpc/CeoCashTodayPage/CeoCashTodayPage'));
const ThirteenWeekCashflowPage = React.lazy(() => import('./pages/Fpc/ThirteenWeekCashflowPage/ThirteenWeekCashflowPage'));
const PlanVsActualPage     = React.lazy(() => import('./pages/Fpc/PlanVsActualPage/PlanVsActualPage'));
const VarianceLogPage      = React.lazy(() => import('./pages/Fpc/VarianceLogPage/VarianceLogPage'));
const BranchPnlPage        = React.lazy(() => import('./pages/Fpc/BranchPnlPage/BranchPnlPage'));
const ConsolidatedPnlPage  = React.lazy(() => import('./pages/Fpc/ConsolidatedPnlPage/ConsolidatedPnlPage'));
const ProjectedBalanceSheetPage = React.lazy(() => import('./pages/Fpc/ProjectedBalanceSheetPage/ProjectedBalanceSheetPage'));
const PlanVoucherPage       = React.lazy(() => import('./pages/Fpc/PlanVoucherPage/PlanVoucherPage'));
const NewBranchSimulatorPage = React.lazy(() => import('./pages/Fpc/NewBranchSimulatorPage/NewBranchSimulatorPage'));
const CostCodePage           = React.lazy(() => import('./pages/Fpc/CostCodePage/CostCodePage'));
const CostPlanPage           = React.lazy(() => import('./pages/Fpc/CostPlanPage/CostPlanPage'));
const FpcCustomerDemoPage    = React.lazy(() => import('./pages/Fpc/FpcCustomerDemoPage/FpcCustomerDemoPage'));
const FpcCostDeclarePage     = React.lazy(() => import('./pages/Fpc/FpcCostDeclarePage/FpcCostDeclarePage'));
const PlanVoucherList        = React.lazy(() => import('./pages/Fpc/PlanVoucherList/PlanVoucherList'));

const PageSuspense = ({ children }: { children: React.ReactNode }) => (
  <React.Suspense fallback={<div className={pageSuspenseStyles.fallback}>Đang tải...</div>}>
    {children}
  </React.Suspense>
);

const AppShell = () => (
  <StandaloneShell>
    <StandaloneMockNav />
    <StandaloneMockTopbar />
    <AppLayout />
  </StandaloneShell>
);

const Root: React.FC<Partial<IRootProps>> = (_rootProps = {}) => (
  <Provider store={store}>
    <MemoryRouter
      initialEntries={[getBrowserRouterPath()]}
      future={{ v7_startTransition: true, v7_relativeSplatPath: true }}
    >
      <MemoryRouterSync />
      <Routes>
        <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>

          {/* ── Dev ───────────────────────────────────────────────── */}
          {showDevNav && (
            <>
              <Route index                              element={<Navigate to="/dev" replace />} />
              <Route path="dev"                         element={<PageSuspense><DevPage /></PageSuspense>} />
              <Route path="tc/dev/tao-du-lieu-mau"      element={<PageSuspense><DevFpcSampleDataPage /></PageSuspense>} />
            </>
          )}

          {/* ── Kế hoạch dòng tiền ─────────────────────────────── */}
          <Route path="tc/kh/du-bao-tien-mat"           element={<PageSuspense><DailyCashForecastPage /></PageSuspense>} />
          <Route path="tc/bc/hom-nay"                   element={<PageSuspense><CeoCashTodayPage /></PageSuspense>} />
          <Route path="tc/kh/dong-tien"                 element={<PageSuspense><ThirteenWeekCashflowPage /></PageSuspense>} />

          {/* ── Kế hoạch & Thực hiện ───────────────────────────── */}
          <Route path="tc/kh/kh-vs-thuc-te"             element={<PageSuspense><PlanVsActualPage /></PageSuspense>} />
          <Route path="tc/bc/nhat-ky-chenh-lech"        element={<PageSuspense><VarianceLogPage /></PageSuspense>} />
          <Route path="tc/kh/ke-hoach"                  element={<PageSuspense><PlanVoucherList /></PageSuspense>} />
          <Route path="tc/kh/ke-hoach/new"              element={<PageSuspense><PlanVoucherPage /></PageSuspense>} />
          <Route path="tc/kh/ke-hoach/:id"              element={<PageSuspense><PlanVoucherPage /></PageSuspense>} />
          <Route path="tc/kh/khai-bao-chi-phi"          element={<PageSuspense><FpcCostDeclarePage /></PageSuspense>} />
          <Route path="tc/kh/chi-phi-du-kien"           element={<PageSuspense><CostPlanPage /></PageSuspense>} />

          {/* ── Phân tích lợi nhuận ────────────────────────────── */}
          <Route path="tc/bc/pnl-chi-nhanh"             element={<PageSuspense><BranchPnlPage /></PageSuspense>} />
          <Route path="tc/bc/pnl-hop-nhat"              element={<PageSuspense><ConsolidatedPnlPage /></PageSuspense>} />
          <Route path="tc/kh/cdkt-du-phong"             element={<PageSuspense><ProjectedBalanceSheetPage /></PageSuspense>} />

          {/* ── Phân tích nâng cao ─────────────────────────────── */}
          <Route path="tc/kh/mo-rong-ch"                element={<PageSuspense><NewBranchSimulatorPage /></PageSuspense>} />
          <Route path="tc/kh/ma-chi-phi"                element={<PageSuspense><CostCodePage /></PageSuspense>} />
          <Route path="tc/fpc/demo"                     element={<PageSuspense><FpcCustomerDemoPage /></PageSuspense>} />

          {/* ── 404 ────────────────────────────────────────────── */}
          <Route path="*"                               element={<SimpleNotFoundPage showDevNav={showDevNav} homePath="/dev" />} />
        </Route>
      </Routes>
    </MemoryRouter>
  </Provider>
);

export default Root;
