/**
 * Standalone dev — global Topbar parity @linm/nav (autohide + title + layout vars).
 */
import React, { useEffect, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import {
  NAV_SET_TITLE,
  NAV_TOPBAR_AUTOHIDE,
  NAV_TOPBAR_LAYOUT_UNLOCK,
  Topbar,
  useResponsive,
  isTopbarAutohideSuppressed,
  readLockedTopbarLayoutInset,
} from '@linm-soft-org/linm-web-common-components';
import { showDevNav } from '../dev/isStandalone';
import styles from './StandaloneMockTopbar.module.css';

const TOPBAR_HEIGHT = 72;
const TOPBAR_HEIGHT_MOBILE = 64;

function resolveTitle(pathname: string): string {
  if (pathname.startsWith('/dev')) return 'Dev Navigation';
  if (pathname.startsWith('/tc/kh/du-bao-tien-mat')) return 'Dự báo tiền mặt hàng ngày';
  if (pathname.startsWith('/tc/bc/hom-nay')) return 'CEO Cash Today';
  if (pathname.startsWith('/tc')) return 'KPI & FPC';
  return 'ERP KPI & FPC';
}

export const StandaloneMockTopbar: React.FC = () => {
  const location = useLocation();
  const { isMobile } = useResponsive();
  const [pageTitle, setPageTitle] = useState(() => resolveTitle(location.pathname));
  const [topbarAutoHidden, setTopbarAutoHidden] = useState(false);
  const [topbarLayoutUnlockTick, setTopbarLayoutUnlockTick] = useState(0);

  useEffect(() => {
    setPageTitle(resolveTitle(location.pathname));
  }, [location.pathname]);

  useEffect(() => {
    const onTitle = (e: Event) => {
      const title = (e as CustomEvent<string>).detail;
      if (typeof title === 'string' && title.trim()) {
        setPageTitle(title);
      } else {
        setPageTitle(resolveTitle(location.pathname));
      }
    };
    window.addEventListener(NAV_SET_TITLE, onTitle);
    return () => window.removeEventListener(NAV_SET_TITLE, onTitle);
  }, []);

  useEffect(() => {
    setTopbarAutoHidden(false);
  }, [location.pathname]);

  useEffect(() => {
    const handler = (e: Event) => {
      if (isTopbarAutohideSuppressed() || readLockedTopbarLayoutInset()) return;
      const hidden = (e as CustomEvent<{ hidden?: boolean }>).detail?.hidden;
      if (typeof hidden === 'boolean') setTopbarAutoHidden(hidden);
    };
    window.addEventListener(NAV_TOPBAR_AUTOHIDE, handler);
    return () => window.removeEventListener(NAV_TOPBAR_AUTOHIDE, handler);
  }, []);

  useEffect(() => {
    const onUnlock = () => setTopbarLayoutUnlockTick((t) => t + 1);
    window.addEventListener(NAV_TOPBAR_LAYOUT_UNLOCK, onUnlock);
    return () => window.removeEventListener(NAV_TOPBAR_LAYOUT_UNLOCK, onUnlock);
  }, []);

  useEffect(() => {
    const topbarVisiblePx = isMobile ? TOPBAR_HEIGHT_MOBILE : TOPBAR_HEIGHT;
    document.documentElement.style.setProperty('--topbar-slide-height', `${topbarVisiblePx}px`);
    const locked = readLockedTopbarLayoutInset();
    const topbarLayoutInset =
      locked ?? (topbarAutoHidden ? '0px' : `${topbarVisiblePx}px`);
    document.documentElement.style.setProperty('--topbar-height', topbarLayoutInset);
    document.documentElement.dataset.topbarAutohide = topbarAutoHidden ? 'true' : 'false';
  }, [isMobile, topbarAutoHidden, topbarLayoutUnlockTick]);

  const showDevLink = showDevNav && !location.pathname.startsWith('/dev');

  return (
    <div
      className={[styles.topbarHost, topbarAutoHidden ? styles.topbarHostHidden : ''].filter(Boolean).join(' ')}
      data-testid="standalone-mock-topbar"
    >
      <Topbar
        title={pageTitle}
        showMenuButton={isMobile}
        onMenuClick={() => window.dispatchEvent(new CustomEvent('linm:nav:toggle-mobile'))}
        rightSlot={
          showDevLink ? (
            <Link to="/dev" className={styles.devLink} title="Dev Navigation" aria-label="Dev Navigation">
              <i className="fas fa-wrench" aria-hidden />
            </Link>
          ) : undefined
        }
      />
    </div>
  );
};

export default StandaloneMockTopbar;
