import React from 'react';
import { Outlet, useLocation, Link } from 'react-router-dom';
import { useResponsive, ReduxToastContainer } from '@linm-soft-org/linm-web-common-components';
import { isStandalone, showDevNav } from '../../../dev/isStandalone';
import styles from './AppLayout.module.css';

const getPageTitle = (pathname: string): string => {
  if (pathname.startsWith('/dev')) return 'Dev Navigation';
  if (pathname.startsWith('/tc/kh/du-bao-tien-mat')) return 'Dự báo tiền mặt hàng ngày';
  if (pathname.startsWith('/tc/bc/hom-nay')) return 'CEO Cash Today';
  if (pathname.startsWith('/tc')) return 'KPI & FPC';
  return 'ERP KPI & FPC';
};

export const AppLayout: React.FC = () => {
  const location = useLocation();
  const { isMobile } = useResponsive();
  const title = getPageTitle(location.pathname);
  const isDevPath = location.pathname.startsWith('/dev');

  if (!isStandalone) {
    // Embedded mode (prod shell) — height:100vh + topbar padding
    return (
      <div className={styles.shell}>
        <main className={styles.mainEmbedded} data-modal-root>
          <Outlet />
        </main>
        {isStandalone && <ReduxToastContainer />}
      </div>
    );
  }

  return (
    <div className={styles.shell}>
      <header className={styles.header}>
        <h1 className={styles.title}>{title}</h1>
        {showDevNav && !isDevPath && (
          <Link to="/dev" className={styles.devLink}>
            Dev
          </Link>
        )}
      </header>
      <main className={styles.mainStandalone} data-modal-root>
        <Outlet />
      </main>
      {isStandalone && <ReduxToastContainer />}
    </div>
  );
};

export default AppLayout;
